import React from 'react';
import { DiscoveryStepIndicator } from '../discovery/DiscoveryStepIndicator.js';
import { AIIcon, CollapseIcon } from './Icons.js';

export interface FitResultsHeaderProps {
    questions?: Array<{ id?: string; question?: string; summary?: string }>;
    answeredIntents?: Record<string, { answer: string; [key: string]: unknown }>;
    onStepClick?: (index: number) => void;
    showCollapseBtn?: boolean;
    isCollapsed?: boolean;
    onCollapseToggle?: () => void;
    showSubtitle?: boolean;
    titleExtra?: React.ReactNode;
}

/**
 * FitResultsHeader - Shared header for all FitResultsPanel states.
 */
export function FitResultsHeader({
    questions = [],
    answeredIntents = {},
    onStepClick,
    showCollapseBtn = false,
    isCollapsed = false,
    onCollapseToggle,
    showSubtitle = false,
    titleExtra = null,
}: FitResultsHeaderProps): JSX.Element {
    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            onCollapseToggle?.();
        }
    };

    return (
        <div className="omniguide-pr-results__header">
            <div className="omniguide-pr-results__header-row">
                <div className="omniguide-pr-results__header-content">
                    <div className="omniguide-pr-results__title-row">
                        <div className="omniguide-pr-results__icon">
                            <AIIcon />
                        </div>
                        {titleExtra ? (
                            <div className="omniguide-pr-results__title-content">
                                <h2 className="omniguide-pr-results__title">Is this the right product for me?</h2>
                                {titleExtra}
                            </div>
                        ) : (
                            <h2 className="omniguide-pr-results__title">Is this the right product for me?</h2>
                        )}
                    </div>
                    {questions.length > 0 && (
                        <div className="omniguide-pr-results__header-pills">
                            <DiscoveryStepIndicator
                                currentStep={-1}
                                totalSteps={questions.length}
                                answeredIntents={answeredIntents}
                                questions={questions}
                                onStepClick={onStepClick}
                            />
                        </div>
                    )}
                </div>
                {showCollapseBtn && onCollapseToggle && (
                    <button
                        type="button"
                        className="omniguide-pr-results__collapse-btn"
                        data-collapsed={isCollapsed}
                        onClick={onCollapseToggle}
                        onKeyDown={handleKeyDown}
                        aria-expanded={!isCollapsed}
                        aria-label={isCollapsed ? 'Expand recommendations' : 'Collapse recommendations'}
                    >
                        <CollapseIcon />
                    </button>
                )}
            </div>
            {showSubtitle && (
                <p className="omniguide-pr-results__subtitle">
                    Based on your answers, here&apos;s our assessment of this product for your needs.
                </p>
            )}
        </div>
    );
}
