import React, { memo } from 'react';
import { formatPrice } from '@swiftotter/omniguide-core';
import { ReviewInsightsToggle } from '../discovery/ReviewInsightsToggle.js';
import { parseMarkdownToHtml } from '../../utils/markdown.js';
import { CheckIcon, XIcon } from './Icons.js';

export interface FitProduct {
    name?: string;
    display_name?: string;
    product_line?: string;
    price?: number | string;
    retail_price?: number | string;
    url?: string;
    image_url?: string;
    sku?: string;
    review_insights?: {
        average_rating?: number;
        review_count?: number;
        summary?: string;
        likes?: string[];
    };
}

export interface ProductComparisonCardProps {
    product?: FitProduct | null;
    /** 'current' | 'alternative' */
    variant: 'current' | 'alternative';
    reasons?: string[];
    reasonsTitle?: string;
    showCta?: boolean;
    /** Callback when the "View This Product" CTA is clicked (DI for analytics) */
    onProductClick?: (name: string, sku: string | undefined, url: string) => void;
}

/**
 * ProductComparisonCard - Reusable card for current product and alternative.
 * Used in the side-by-side comparison grid when product is not a good fit.
 */
export const ProductComparisonCard = memo(function ProductComparisonCard({
    product,
    variant,
    reasons = [],
    reasonsTitle,
    showCta = false,
    onProductClick,
}: ProductComparisonCardProps): JSX.Element | null {
    if (!product) return null;

    const {
        name,
        display_name: displayName,
        product_line: productLine,
        price,
        retail_price: retailPrice,
        url,
        image_url: imageUrl,
        review_insights: reviewInsights,
    } = product;

    const productName = name ?? displayName ?? 'Product';
    const rawBrand = productLine ?? '';
    const brand = rawBrand;
    // Strip brand prefix from product name to avoid visual duplication (brand shown on its own line)
    const cleanProductName = (rawBrand && productName.toLowerCase().startsWith(rawBrand.toLowerCase() + ' '))
        ? productName.slice(rawBrand.length).trimStart() || productName
        : productName;
    const productUrl = url ?? '#';
    const productImage = imageUrl ?? '';
    const rating = reviewInsights?.average_rating ?? 0;
    const reviewCount = reviewInsights?.review_count ?? 0;

    const isAlternative = variant === 'alternative';
    const badgeClassName = isAlternative
        ? 'omniguide-pr-comparison__badge omniguide-pr-comparison__badge--alternative'
        : 'omniguide-pr-comparison__badge omniguide-pr-comparison__badge--current';
    const badgeText = isAlternative ? 'Recommended' : 'Current Product';
    const titleClassName = isAlternative
        ? 'omniguide-pr-comparison__reasons-title omniguide-pr-comparison__reasons-title--better'
        : 'omniguide-pr-comparison__reasons-title omniguide-pr-comparison__reasons-title--not-fit';
    const iconClassName = isAlternative
        ? 'omniguide-pr-comparison__reason-icon omniguide-pr-comparison__reason-icon--better'
        : 'omniguide-pr-comparison__reason-icon omniguide-pr-comparison__reason-icon--not-fit';
    const ReasonIcon = isAlternative ? CheckIcon : XIcon;

    return (
        <div className="omniguide-pr-comparison__card">
            {/* Image Section with Badge */}
            <div className="omniguide-pr-comparison__image-section">
                {productImage && (
                    <img
                        src={productImage}
                        alt={cleanProductName}
                        className="omniguide-pr-comparison__image"
                    />
                )}
                <span className={badgeClassName}>{badgeText}</span>
            </div>

            {/* Content Section */}
            <div className="omniguide-pr-comparison__content">
                {/* Brand and Rating Row */}
                <div className="omniguide-pr-comparison__brand-row">
                    {brand && <p className="omniguide-pr-comparison__brand">{brand}</p>}
                    {rating > 0 && (
                        <ReviewInsightsToggle
                            rating={rating}
                            reviewCount={reviewCount}
                            summary={reviewInsights?.summary}
                            likes={reviewInsights?.likes}
                            productName={cleanProductName}
                            productSku={product.sku}
                        />
                    )}
                </div>

                {/* Product Name */}
                <h4 className="omniguide-pr-comparison__name">{cleanProductName}</h4>

                {/* Price Row */}
                <div className="omniguide-pr-comparison__price-row">
                    <div className="omniguide-pr-comparison__price-group">
                        {price && <span className="omniguide-pr-comparison__price">{formatPrice(price)}</span>}
                        {retailPrice && Number(retailPrice) > Number(price) && (
                            <span className="omniguide-pr-comparison__price omniguide-pr-comparison__price--original">
                                {formatPrice(retailPrice)}
                            </span>
                        )}
                    </div>
                </div>

                {/* Divider */}
                <div className="omniguide-pr-comparison__divider" />

                {/* Reasons Section */}
                {reasons.length > 0 && (
                    <div className="omniguide-pr-comparison__reasons-section">
                        <h5 className={titleClassName}>{reasonsTitle}</h5>
                        <ul className="omniguide-pr-comparison__reasons-list">
                            {reasons.map((reason, index) => (
                                <li key={index} className="omniguide-pr-comparison__reason-item">
                                    <div className={iconClassName}>
                                        <ReasonIcon />
                                    </div>
                                    <span dangerouslySetInnerHTML={parseMarkdownToHtml(reason)} />
                                </li>
                            ))}
                        </ul>
                    </div>
                )}

                {/* CTA Button (only for alternative) */}
                {showCta && productUrl && (
                    <div className="omniguide-pr-comparison__cta-section">
                        <a
                            href={productUrl}
                            className="omniguide-pr-comparison__view-btn"
                            onClick={(e) => {
                                e.stopPropagation();
                                onProductClick?.(cleanProductName, product.sku, productUrl);
                            }}
                        >
                            View This Product
                        </a>
                    </div>
                )}
            </div>
        </div>
    );
});
