/**
 * BCProductQuestionnaire — Conversational product fit questionnaire for BigCommerce.
 *
 * Ported from theme `product-recommendations/components/ProductQuestionnaire.jsx`.
 * Uses SDK hooks + components with BC-specific DI.
 */

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import {
  DiscoveryQuestionnaire as DefaultDiscoveryQuestionnaire,
  FitResultsPanel as DefaultFitResultsPanel,
  ProductQuestionSkeleton,
  QuestionnaireTeaser,
  useOmniguideContext,
  useComponent,
  type FeedbackData,
  type AnsweredQuestionEntry,
  type DiscoveryQuestion,
} from '@swiftotter/omniguide-react';
import { FLOW_STATES } from '@swiftotter/omniguide-core';
import { useBCProductQuestions } from '../hooks/useBCProductQuestions.js';
import { useBCProductWebSocket } from '../hooks/useBCProductWebSocket.js';

// ── Types ──────────────────────────────────────────────────────────

export interface BCProductQuestionnaireProps {
  productSku: string;
  onSuggestedQuestionsLoad?: (questions: string[]) => void;
  onNotFitResult?: (isNotFit: boolean) => void;
  isCollapsed?: boolean;
  onCollapseToggle?: () => void;
}

// ── Helper: scroll to element ──────────────────────────────────────

function scrollToElement(element: HTMLElement | null): void {
  if (!element) return;
  setTimeout(() => {
    if (!element) return;
    const header = document.querySelector('header');
    const headerHeight = header ? (header as HTMLElement).offsetHeight : 0;
    const rect = element.getBoundingClientRect();
    const scrollTop = window.pageYOffset || document.documentElement.scrollTop;
    const elementTop = rect.top + scrollTop;
    const targetScroll = elementTop - headerHeight;

    if (rect.top < headerHeight) {
      window.scrollTo({ top: Math.max(0, targetScroll), behavior: 'smooth' });
    }
  }, 100);
}

// ── Component ──────────────────────────────────────────────────────

export function BCProductQuestionnaire({
  productSku,
  onSuggestedQuestionsLoad,
  onNotFitResult,
  isCollapsed: propIsCollapsed = false,
  onCollapseToggle: propOnCollapseToggle,
}: BCProductQuestionnaireProps): JSX.Element {
  const DiscoveryQuestionnaire = useComponent('DiscoveryQuestionnaire', DefaultDiscoveryQuestionnaire);
  const FitResultsPanel = useComponent('FitResultsPanel', DefaultFitResultsPanel);

  const { config, feedbackApi } = useOmniguideContext();
  const teaserEnabled = config.features?.questionnaireTeaser?.productFit ?? false;
  const containerRef = useRef<HTMLDivElement>(null);
  const shouldScrollToTopRef = useRef(false);

  // Fetch first question from REST API
  const { questions: initialQuestions, productData, loading: questionsLoading, hasQuestions, error: questionsError, retry: retryQuestions } =
    useBCProductQuestions(productSku);

  // WebSocket for conversational flow
  const {
    flowState,
    currentQuestion: wsQuestion,
    questionNumber,
    answeredQuestions,
    fitResult,
    isLoading: evaluationLoading,
    error: evaluationError,
    getStatusMessage,
    startConversation,
    resumeSession,
    submitAnswer,
    submitOtherAnswer,
    clearOtherError,
    resetConversation,
    disconnect,
    otherValidationError,
    clarificationPrompt,
    isOtherProcessing,
    hasStoredSession,
  } = useBCProductWebSocket({ productTypeId: productData?.productTypeId as number | string | null });

  // Local state
  const [noQuestions, setNoQuestions] = useState(false);
  const [resultsCollapsed, setResultsCollapsed] = useState(false);
  const [resultsTruncated, setResultsTruncated] = useState(false);
  const [teaserExpanded, setTeaserExpanded] = useState(false);

  // First question from REST API
  const firstQuestion = initialQuestions.length > 0 ? initialQuestions[0] : null;

  // Current question to display
  const currentQuestion = useMemo(() => {
    if (
      flowState === FLOW_STATES.IDLE ||
      flowState === FLOW_STATES.LOADING_FIRST ||
      flowState === FLOW_STATES.SHOWING_FIRST
    ) {
      return firstQuestion;
    }
    return wsQuestion;
  }, [flowState, firstQuestion, wsQuestion]);

  // Should show questionnaire?
  const showQuestionnaire = useMemo(() => {
    if (!hasQuestions) return false;
    const idleOrFirst = flowState === FLOW_STATES.IDLE || flowState === FLOW_STATES.SHOWING_FIRST;
    const questioning = flowState === FLOW_STATES.QUESTIONING && wsQuestion;
    return (idleOrFirst && firstQuestion) || questioning;
  }, [hasQuestions, flowState, firstQuestion, wsQuestion]);

  // Should show results?
  const showResults = useMemo(() => {
    return (
      flowState === FLOW_STATES.LOADING_RESULTS ||
      flowState === FLOW_STATES.COMPLETE ||
      flowState === FLOW_STATES.ERROR
    );
  }, [flowState]);

  // Questions array for StepIndicator
  const questionsForIndicator = useMemo(
    () => answeredQuestions.map((aq) => aq.question),
    [answeredQuestions],
  );

  // AnsweredIntents for StepIndicator
  const answeredIntentsForIndicator = useMemo(() => {
    const intents: Record<string, { answer: string; [key: string]: unknown }> = {};
    answeredQuestions.forEach((aq) => {
      const qId = (aq.question as Record<string, unknown>)?.['id'];
      if (qId) {
        intents[String(qId)] = aq.answer as { answer: string };
      }
    });
    return intents;
  }, [answeredQuestions]);

  // Effective collapsed state
  const effectiveCollapsed = propIsCollapsed || resultsCollapsed;

  // Hide component if no questions
  useEffect(() => {
    if (!questionsLoading && !hasQuestions) {
      setNoQuestions(true);
    }
  }, [questionsLoading, hasQuestions]);

  // Resume stored session on mount
  useEffect(() => {
    if (
      !questionsLoading &&
      flowState === FLOW_STATES.IDLE &&
      hasStoredSession() &&
      productSku
    ) {
      // Auto-expand teaser when resuming a stored session
      if (teaserEnabled && !teaserExpanded) setTeaserExpanded(true);
      resumeSession(productSku);
    }
  }, [questionsLoading, flowState, hasStoredSession, resumeSession, productSku]);

  // Pass suggested questions to parent
  useEffect(() => {
    if (productData?.suggestedQuestions?.length && onSuggestedQuestionsLoad) {
      onSuggestedQuestionsLoad(productData.suggestedQuestions);
    }
  }, [productData, onSuggestedQuestionsLoad]);

  // Notify parent of not-fit result (for layout change)
  useEffect(() => {
    if (fitResult && flowState === FLOW_STATES.COMPLETE) {
      const result = fitResult as Record<string, unknown>;
      const fitEval = result['fitEvaluation'] as Record<string, unknown> | undefined;
      const isNotFit = fitEval?.['is_good_fit'] === false;
      onNotFitResult?.(isNotFit);
    } else if (!fitResult) {
      onNotFitResult?.(false);
    }
  }, [fitResult, flowState, onNotFitResult]);

  // Handle answer selection
  const handleSelectAnswer = useCallback(
    (questionId: string, answer: { id?: string | number; text: string }) => {
      if (!currentQuestion) return;

      const answerData = {
        questionId: String(questionId),
        answerId: answer.id != null ? String(answer.id) : null,
        answerText: answer.text,
      };

      const q = currentQuestion as Record<string, unknown>;
      if (flowState === FLOW_STATES.IDLE || flowState === FLOW_STATES.SHOWING_FIRST) {
        startConversation(productSku, answerData, q);
      } else if (flowState === FLOW_STATES.QUESTIONING) {
        submitAnswer(answerData.questionId, answerData.answerId, answerData.answerText, q);
      }
    },
    [flowState, currentQuestion, productSku, startConversation, submitAnswer],
  );

  // Handle "Other" answer
  const handleOtherSubmit = useCallback(
    (otherText: string) => {
      if (!currentQuestion) return;
      const q = currentQuestion as Record<string, unknown>;
      const qId = String(q['id']);

      if (flowState === FLOW_STATES.IDLE || flowState === FLOW_STATES.SHOWING_FIRST) {
        const answerData = { questionId: qId, answerId: null as string | null, answerText: otherText };
        startConversation(productSku, answerData, q);
      } else if (flowState === FLOW_STATES.QUESTIONING) {
        submitOtherAnswer(qId, otherText, q);
      }
    },
    [currentQuestion, flowState, productSku, startConversation, submitOtherAnswer],
  );

  // Handle start over
  const handleBack = useCallback(() => {
    shouldScrollToTopRef.current = true;
    resetConversation();
    setResultsCollapsed(false);
    setResultsTruncated(false);
  }, [resetConversation]);

  const handleResultsStepClick = useCallback(() => {
    handleBack();
  }, [handleBack]);

  // Scroll on question change
  useEffect(() => {
    if (showQuestionnaire) {
      scrollToElement(containerRef.current);
    }
  }, [showQuestionnaire, questionNumber]);

  // Scroll after returning from results
  useEffect(() => {
    if (shouldScrollToTopRef.current && !showResults) {
      shouldScrollToTopRef.current = false;
      scrollToElement(containerRef.current);
    }
  }, [showResults]);

  // Collapse toggle
  const handleCollapseToggle = useCallback(() => {
    if (propOnCollapseToggle) {
      propOnCollapseToggle();
    } else {
      setResultsCollapsed((prev) => !prev);
    }
  }, [propOnCollapseToggle]);

  const handleTruncatedToggle = useCallback(() => {
    setResultsTruncated((prev) => !prev);
  }, []);

  // Cleanup
  useEffect(() => {
    return () => {
      disconnect();
    };
  }, [disconnect]);

  // Feedback submit handler using feedbackApi from context
  const handleFeedbackSubmit = useCallback(
    async (data: FeedbackData) => {
      if (!feedbackApi) throw new Error('Feedback API not available');
      return feedbackApi.submitFeedback({
        entityId: data.entity_id,
        entityType: data.entity_type as 'message' | 'product_recommendation' | 'category_recommendation',
        vote: data.vote as 1 | -1,
        comment: data.comment ?? '',
        context: data.context ?? {},
      });
    },
    [feedbackApi],
  );

  // Container class
  const containerClassName = noQuestions && !questionsError
    ? 'omniguide-pr-container omniguide-pr-container--collapsed'
    : 'omniguide-pr-container';

  // Build questionnaire props
  const questionsForQuestionnaire = currentQuestion ? [currentQuestion] : [];
  const currentAnsweredIntents = {};

  const questionnaireContent = (
    <>
      {/* Loading skeleton */}
      {questionsLoading && <ProductQuestionSkeleton />}

      {/* Error state when questions fail to load */}
      {!questionsLoading && questionsError && !hasQuestions && (
        <div className="omniguide-pr-error">
          <h3 className="omniguide-pr-error__title">Unable to connect</h3>
          <p className="omniguide-pr-error__text">
            The service is currently unavailable. Please try again in a moment.
          </p>
          <button
            type="button"
            className="omniguide-pr-error__retry-btn"
            onClick={retryQuestions}
          >
            <span>Try Again</span>
          </button>
        </div>
      )}

      {/* Questionnaire - single question at a time */}
      {!questionsLoading && showQuestionnaire && currentQuestion && (
        <DiscoveryQuestionnaire
          questions={questionsForQuestionnaire as DiscoveryQuestion[]}
          currentStep={0}
          answeredIntents={currentAnsweredIntents}
          onSelectAnswer={handleSelectAnswer}
          onNext={() => {}}
          onPrevious={() => {}}
          onSubmit={() => {}}
          onStepClick={() => {}}
          dynamicMode={true}
          answeredQuestions={answeredQuestions as AnsweredQuestionEntry[]}
          questionNumber={answeredQuestions.length + 1}
          onOtherSubmit={handleOtherSubmit}
          isOtherProcessing={isOtherProcessing}
          otherError={otherValidationError as { message: string } | null}
          clarificationPrompt={clarificationPrompt}
          onClearOtherError={clearOtherError}
          classPrefix="omniguide-pr"
        />
      )}

      {/* Loading state between questions */}
      {!questionsLoading &&
        !showQuestionnaire &&
        !showResults &&
        (flowState === FLOW_STATES.CONNECTING ||
          (flowState === FLOW_STATES.QUESTIONING && !wsQuestion)) && (
          <div className="omniguide-pr-questionnaire">
            <ProductQuestionSkeleton />
          </div>
        )}
    </>
  );

  // Show teaser when enabled and questionnaire is in its initial idle state
  const showTeaser = teaserEnabled && !teaserExpanded && flowState === FLOW_STATES.IDLE && !showResults;

  return (
    <div ref={containerRef} className={containerClassName}>
      {showTeaser ? (
        <QuestionnaireTeaser
          classPrefix="omniguide-pr"
          onExpand={() => setTeaserExpanded(true)}
        >
          {questionnaireContent}
        </QuestionnaireTeaser>
      ) : (
        questionnaireContent
      )}

      {/* Results panel */}
      {showResults && (
        <FitResultsPanel
          fitResult={fitResult as Record<string, unknown>}
          isLoading={evaluationLoading || flowState === FLOW_STATES.LOADING_RESULTS}
          error={evaluationError as { message?: string } | undefined}
          statusMessage={getStatusMessage() ?? undefined}
          onBack={handleBack}
          questions={questionsForIndicator as Array<{ id?: string; question?: string; summary?: string }>}
          answeredIntents={answeredIntentsForIndicator}
          onStepClick={handleResultsStepClick}
          isCollapsed={effectiveCollapsed}
          onCollapseToggle={handleCollapseToggle}
          isTruncated={resultsTruncated}
          onTruncatedToggle={handleTruncatedToggle}
          onProductClick={(name, sku, url) => {
            config.analyticsAdapter?.track('product_rec_product_click', {
              product_name: name,
              product_sku: sku,
              product_url: url,
              timestamp: new Date().toISOString(),
            });
          }}
          onStartOver={() => {
            config.analyticsAdapter?.track('product_rec_start_over', {
              timestamp: new Date().toISOString(),
            });
          }}
          onFeedbackSubmit={handleFeedbackSubmit}
        />
      )}
    </div>
  );
}
