import React from 'react';
import { ProductComparisonCard as DefaultProductComparisonCard } from './ProductComparisonCard.js';
import type { FitProduct } from './ProductComparisonCard.js';
import { useComponent } from '../../hooks/useComponent.js';

export interface NotFitResultProps {
    currentProduct?: FitProduct | null;
    fitExplanation?: {
        why_not_good_fit?: string[];
    };
    alternative?: FitProduct & {
        why_better_for_you?: string[];
    };
    /** DI: analytics callback when user clicks alternative product */
    onProductClick?: (name: string, sku: string | undefined, url: string) => void;
}

/**
 * Not fit result component.
 * Displays when the current product is not a good match.
 * Shows a side-by-side comparison with the recommended alternative.
 */
export function NotFitResult({ currentProduct, fitExplanation, alternative, onProductClick }: NotFitResultProps): JSX.Element {
    const ProductComparisonCard = useComponent('ProductComparisonCard', DefaultProductComparisonCard);

    const whyNotGoodFit = fitExplanation?.why_not_good_fit ?? [];
    const whyBetterForYou = alternative?.why_better_for_you ?? [];

    return (
        <div className="omniguide-pr-comparison">
            {/* Current Product Card */}
            <ProductComparisonCard
                product={currentProduct}
                variant="current"
                reasons={whyNotGoodFit}
                reasonsTitle="Why this isn't the best fit:"
                showCta={false}
            />

            {/* Alternative Product Card */}
            {alternative && (
                <ProductComparisonCard
                    product={alternative}
                    variant="alternative"
                    reasons={whyBetterForYou}
                    reasonsTitle="Why this would work better for you:"
                    showCta={true}
                    onProductClick={onProductClick}
                />
            )}
        </div>
    );
}
