import React from 'react';
import { DiscoveryFeedbackWidget } from '../discovery/DiscoveryFeedbackWidget.js';
import type { FeedbackData } from '../discovery/DiscoveryFeedbackWidget.js';
import { StartOverIcon } from './Icons.js';
import type { FitProduct } from './ProductComparisonCard.js';

export interface FitResultsFooterProps {
    fitResult: {
        currentProduct?: FitProduct | null;
    };
    alternative?: FitProduct | null;
    onBack: () => void;
    /** DI: analytics callback for start-over action */
    onStartOver?: () => void;
    /** DI: callback for feedback submission */
    onFeedbackSubmit: (data: FeedbackData) => Promise<unknown>;
}

/**
 * FitResultsFooter - Footer with feedback, attribution, and start-over button.
 */
export function FitResultsFooter({ fitResult, alternative, onBack, onStartOver, onFeedbackSubmit }: FitResultsFooterProps): JSX.Element {
    return (
        <div className="omniguide-pr-results__footer">
            <DiscoveryFeedbackWidget
                entityId={alternative?.sku ?? fitResult.currentProduct?.sku ?? ''}
                entityType="product_recommendation"
                context={{
                    product_name: alternative
                        ? (alternative.name ?? alternative.display_name)
                        : (fitResult.currentProduct?.name ?? fitResult.currentProduct?.display_name),
                    fit_status: alternative ? 'poor_fit_alternative' : 'good_fit',
                }}
                onSubmit={onFeedbackSubmit}
            />
            <div className="omniguide-pr-results__footer-text">Powered by AI</div>
            <button
                type="button"
                onClick={() => {
                    onStartOver?.();
                    onBack();
                }}
                className="omniguide-pr-results__start-over"
            >
                <div className="omniguide-pr-results__start-over-icon">
                    <StartOverIcon />
                </div>
                Start Over
            </button>
        </div>
    );
}
