import React from 'react';
import { parseMarkdownToHtml } from '../../utils/markdown.js';
import { ThumbsUpIcon, CheckIcon } from './Icons.js';

export interface GoodFitResultProps {
    fitExplanation?: {
        why_good_fit?: string[];
    };
}

/**
 * Good fit result component.
 * Displays when the current product is a good match for the user.
 */
export function GoodFitResult({ fitExplanation }: GoodFitResultProps): JSX.Element {
    const reasons = fitExplanation?.why_good_fit ?? [];

    return (
        <div className="omniguide-pr-fit omniguide-pr-fit--good">
            <div className="omniguide-pr-fit__content">
                <div className="omniguide-pr-fit__heading-container">
                    <div className="omniguide-pr-fit__icon--good">
                        <ThumbsUpIcon />
                    </div>
                    <h3 className="omniguide-pr-fit__title omniguide-pr-fit__title--good">Great Match!</h3>
                </div>
                {reasons.length > 0 && (
                    <ul className="omniguide-pr-fit__reasons-list">
                        {reasons.map((reason, index) => (
                            <li key={index} className="omniguide-pr-fit__reason-item">
                                <div className="omniguide-pr-fit__check-icon">
                                    <CheckIcon />
                                </div>
                                <span dangerouslySetInnerHTML={parseMarkdownToHtml(reason)} />
                            </li>
                        ))}
                    </ul>
                )}
            </div>
        </div>
    );
}
