/**
 * useBCProductQuestions — Fetches product questions from REST API.
 *
 * Ported from theme `product-recommendations/hooks/useProductQuestions.js`.
 * Uses omniguide-core `fetchProductQuestions` with config from OmniguideProvider.
 */

import { useState, useEffect, useCallback } from 'react';
import { fetchProductQuestions, createScopedLogger, type DiscoveryQuestion } from '@swiftotter/omniguide-core';
import { useOmniguideContext } from '@swiftotter/omniguide-react';

const log = createScopedLogger('useBCProductQuestions');

// ── Types ──────────────────────────────────────────────────────────

export interface ProductData {
  productId: unknown;
  productSku: string;
  productName: string;
  productTypeId: unknown;
  productTypeName: string;
  suggestedQuestions: string[];
}

export interface UseBCProductQuestionsReturn {
  questions: DiscoveryQuestion[];
  productData: ProductData | null;
  loading: boolean;
  error: Error | null;
  hasQuestions: boolean;
  /** Retry fetching questions after an error */
  retry: () => void;
}

// ── Hook ───────────────────────────────────────────────────────────

export function useBCProductQuestions(
  productSku: string,
): UseBCProductQuestionsReturn {
  const { config } = useOmniguideContext();

  const [questions, setQuestions] = useState<DiscoveryQuestion[]>([]);
  const [productData, setProductData] = useState<ProductData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);
  const [retryCount, setRetryCount] = useState(0);

  const retry = useCallback(() => setRetryCount((c) => c + 1), []);

  useEffect(() => {
    const loadQuestions = async () => {
      setLoading(true);
      setError(null);

      try {
        if (!productSku) {
          log.warn('No product SKU provided');
          setQuestions([]);
          setLoading(false);
          return;
        }

        const questionConfig = {
          apiBaseUrl: config.apiBaseUrl,
          websiteId: config.websiteId,
        };

        const data = await fetchProductQuestions(questionConfig, productSku);

        setProductData({
          productId: data['product_id'],
          productSku: data['product_sku'] as string,
          productName: data['product_name'] as string,
          productTypeId: data['product_type_id'],
          productTypeName: data['product_type_name'] as string,
          suggestedQuestions: (data['suggested_questions'] as string[]) || [],
        });

        setQuestions(data.questions);
      } catch (err) {
        log.error('Error loading product questions:', err);
        setError(err instanceof Error ? err : new Error(String(err)));
        setQuestions([]);
      } finally {
        setLoading(false);
      }
    };

    loadQuestions();
  }, [productSku, config.apiBaseUrl, config.websiteId, retryCount]);

  return {
    questions,
    productData,
    loading,
    error,
    hasQuestions: questions.length > 0,
    retry,
  };
}
